async function getDashboardStats(companyId: string) {
  try {
    // Get total products
    const products = await sql`
      SELECT COUNT(*) as count FROM products WHERE company_id = ${companyId} AND is_active = true
    `

    // Get total clients
    const clients = await sql`
      SELECT COUNT(*) as count FROM clients WHERE company_id = ${companyId} AND is_active = true
    `

    // Get today's sales
    const todaySales = await sql`
      SELECT COALESCE(SUM(total_amount), 0) as total, COUNT(*) as count
      FROM sales_orders 
      WHERE company_id = ${companyId} 
      AND DATE(created_at) = CURRENT_DATE
      AND status != 'cancelled'
    `

    // Get pending deliveries
    const pendingDeliveries = await sql`
      SELECT COUNT(*) as count 
      FROM delivery_tours 
      WHERE company_id = ${companyId} 
      AND status IN ('planned', 'in_progress')
    `

    // Get low stock alerts
    const lowStockAlerts = await sql`
      SELECT COUNT(*) as count 
      FROM alerts 
      WHERE company_id = ${companyId} 
      AND alert_type = 'low_stock'
      AND is_read = false
    `

    // Get recent sales
    const recentSales = await sql`
      SELECT so.*, c.name as client_name
      FROM sales_orders so
      LEFT JOIN clients c ON so.client_id = c.id
      WHERE so.company_id = ${companyId}
      ORDER BY so.created_at DESC
      LIMIT 5
    `

    return {
      totalProducts: Number(products[0]?.count || 0),
      totalClients: Number(clients[0]?.count || 0),
      todaySalesTotal: Number(todaySales[0]?.total || 0),
      todaySalesCount: Number(todaySales[0]?.count || 0),
      pendingDeliveries: Number(pendingDeliveries[0]?.count || 0),
      lowStockAlerts: Number(lowStockAlerts[0]?.count || 0),
      recentSales: recentSales || [],
    }
  } catch (error) {
    console.error('Error fetching dashboard stats:', error)
    return {
      totalProducts: 0,
      totalClients: 0,
      todaySalesTotal: 0,
      todaySalesCount: 0,
      pendingDeliveries: 0,
      lowStockAlerts: 0,
      recentSales: [],
    }
  }
}

function formatCurrency(amount: number, currency = 'XOF') {
  return new Intl.NumberFormat('fr-FR', {
    style: 'currency',
    currency,
    minimumFractionDigits: 0,
  }).format(amount)
}

